# OcxState에서 한글/영문 텍스트 추출 (바이트 수준)
param([string]$ResxPath)

[xml]$xml = Get-Content $ResxPath -Encoding UTF8
foreach ($data in $xml.root.data) {
    if ($data.name -match '\.OcxState$') {
        $ctrlName = $data.name -replace '\.OcxState$', ''
        $base64 = $data.value.Trim()
        $bytes = [Convert]::FromBase64String($base64)

        # UTF-16LE로 읽을 수 있는 연속 문자열 찾기
        $texts = @()
        $i = 0
        while ($i -lt $bytes.Length - 1) {
            $ch = [BitConverter]::ToUInt16($bytes, $i)
            # 한글(AC00-D7A3) 또는 ASCII printable(0020-007E) 범위
            if (($ch -ge 0x0020 -and $ch -le 0x007E) -or ($ch -ge 0xAC00 -and $ch -le 0xD7A3)) {
                $start = $i
                $str = ""
                while ($i -lt $bytes.Length - 1) {
                    $ch = [BitConverter]::ToUInt16($bytes, $i)
                    if (($ch -ge 0x0020 -and $ch -le 0x007E) -or ($ch -ge 0xAC00 -and $ch -le 0xD7A3)) {
                        $str += [char]$ch
                        $i += 2
                    } else {
                        break
                    }
                }
                if ($str.Length -ge 2 -and $str -notmatch '^\s+$') {
                    $texts += $str.Trim()
                }
            } else {
                $i += 2
            }
        }

        if ($texts.Count -gt 0) {
            Write-Output "$ctrlName : $($texts -join ' | ')"
        }
    }
}

