        foreach ($m in $matches) {
            $t = $m.Value.Trim()
            if ($t.Length -ge 2) { $texts += $t }
        }
        if ($texts.Count -gt 0) {
            Write-Output "${ctrlName}: $($texts -join ' | ')"
        }
    }
}

