# OcxState에서 BSTR(4바이트 길이 + UTF-16LE 문자열) 추출
param([string]$ResxPath)

[xml]$xml = Get-Content $ResxPath -Encoding UTF8
foreach ($data in $xml.root.data) {
    if ($data.name -match '\.OcxState$') {
        $ctrlName = $data.name -replace '\.OcxState$', ''
        $base64 = $data.value.Trim()
        $bytes = [Convert]::FromBase64String($base64)

        $texts = @()
        for ($i = 0; $i -lt $bytes.Length - 5; $i++) {
            # 4바이트 리틀엔디안 길이 읽기
            $len = [BitConverter]::ToInt32($bytes, $i)
            # BSTR 길이는 바이트 단위, 합리적 범위 (2~200바이트, 짝수)
            if ($len -ge 2 -and $len -le 200 -and $len % 2 -eq 0 -and ($i + 4 + $len) -le $bytes.Length) {
                $strBytes = $bytes[($i+4)..($i+3+$len)]
                $str = [System.Text.Encoding]::Unicode.GetString($strBytes)
                # 한글이 포함된 문자열만
                if ($str -match '[\uAC00-\uD7A3]' -and $str -notmatch '[\x00-\x1F]') {
                    $texts += $str
                }
            }
        }
        if ($texts.Count -gt 0) {
            $unique = $texts | Select-Object -Unique
            Write-Output "${ctrlName}: $($unique -join ' | ')"
        }
    }
}

