# 버튼/라벨 컨트롤의 OcxState를 hex+ASCII로 덤프
param([string]$ResxPath, [string]$CtrlName = "ascButtonExit")

[xml]$xml = Get-Content $ResxPath -Encoding UTF8
foreach ($data in $xml.root.data) {
    if ($data.name -eq "$CtrlName.OcxState") {
        $base64 = $data.value.Trim()
        $bytes = [Convert]::FromBase64String($base64)
        Write-Output "=== $CtrlName ($($bytes.Length) bytes) ==="

        # Hex dump with ASCII
        for ($i = 0; $i -lt [Math]::Min($bytes.Length, 1024); $i += 16) {
            $hex = ""
            $ascii = ""
            for ($j = 0; $j -lt 16 -and ($i+$j) -lt $bytes.Length; $j++) {
                $b = $bytes[$i+$j]
                $hex += "{0:X2} " -f $b
                if ($b -ge 0x20 -and $b -le 0x7E) { $ascii += [char]$b }
                else { $ascii += "." }
            }
            Write-Output ("{0:X4}: {1,-48} {2}" -f $i, $hex, $ascii)
        }
    }
}

