# OcxState에서 CP949 한글 텍스트 추출 (바이트 수준 스캔)
param([string]$ResxPath)

$enc = [System.Text.Encoding]::GetEncoding(949)

function Is-CP949LeadByte($b) {
    return ($b -ge 0x81 -and $b -le 0xFE)
}

function Is-CP949TrailByte($b) {
    return (($b -ge 0x41 -and $b -le 0x5A) -or ($b -ge 0x61 -and $b -le 0x7A) -or ($b -ge 0x81 -and $b -le 0xFE))
}

[xml]$xml = Get-Content $ResxPath -Encoding UTF8
foreach ($data in $xml.root.data) {
    if ($data.name -match '\.OcxState$') {
        $ctrlName = $data.name -replace '\.OcxState$', ''
        $base64 = $data.value.Trim()
        $bytes = [Convert]::FromBase64String($base64)

        $texts = @()
        $i = 0
        while ($i -lt $bytes.Length) {
            $b = $bytes[$i]
            # CP949 한글 리드바이트 또는 ASCII printable 시작
            if ((Is-CP949LeadByte $b) -or ($b -ge 0x20 -and $b -le 0x7E)) {
                $start = $i
                $strBytes = @()
                $hasKorean = $false
                while ($i -lt $bytes.Length) {
                    $b = $bytes[$i]
                    if ((Is-CP949LeadByte $b) -and ($i + 1) -lt $bytes.Length -and (Is-CP949TrailByte $bytes[$i+1])) {
                        $strBytes += $bytes[$i]
                        $strBytes += $bytes[$i+1]
                        $hasKorean = $true
                        $i += 2
                    } elseif ($b -ge 0x20 -and $b -le 0x7E) {
                        $strBytes += $b
                        $i++
                    } else {
                        break
                    }
                }
                if ($hasKorean -and $strBytes.Count -ge 2) {
                    $str = $enc.GetString([byte[]]$strBytes).Trim()
                    if ($str.Length -ge 2) {
                        $texts += $str
                    }
                } else {
                    $i = $start + 1
                }
            } else {
                $i++
            }
        }

        if ($texts.Count -gt 0) {
            $unique = $texts | Select-Object -Unique
            Write-Output "${ctrlName}: $($unique -join ' | ')"
        }
    }
}

